import React, { useState } from 'react';
import styled from 'styled-components';
import { 
  CreditCard, 
  Database, 
  Grid, 
  Bot,
  CheckCircle,
  AlertCircle
} from 'lucide-react';
import integrationsService from '../services/integrationsService';

const Container = styled.div`
  padding: 2rem;
  max-width: 1200px;
  margin: 0 auto;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 3rem;
`;

const Title = styled.h1`
  font-size: 2.5rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 1rem;
`;

const Subtitle = styled.p`
  font-size: 1.25rem;
  color: #64748b;
  max-width: 600px;
  margin: 0 auto;
`;

const IntegrationsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));
  gap: 2rem;
  margin-bottom: 3rem;
`;

const IntegrationCard = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 2rem;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  border: 1px solid #e2e8f0;
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 15px rgba(0, 0, 0, 0.1);
  }
`;

const CardHeader = styled.div`
  display: flex;
  align-items: center;
  margin-bottom: 1.5rem;
`;

const CardIcon = styled.div`
  width: 3rem;
  height: 3rem;
  border-radius: 0.75rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  margin-right: 1rem;
`;

const CardTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
`;

const CardDescription = styled.p`
  color: #64748b;
  margin-bottom: 1.5rem;
  line-height: 1.6;
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
  gap: 1rem;
`;

const FormGroup = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
`;

const Label = styled.label`
  font-weight: 500;
  color: #334155;
`;

const Input = styled.input`
  padding: 0.75rem;
  border: 1px solid #cbd5e1;
  border-radius: 0.5rem;
  font-size: 1rem;
  
  &:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
  }
`;

const TextArea = styled.textarea`
  padding: 0.75rem;
  border: 1px solid #cbd5e1;
  border-radius: 0.5rem;
  font-size: 1rem;
  min-height: 100px;
  font-family: inherit;
  
  &:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
  }
`;

const Button = styled.button`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 0.75rem 1.5rem;
  border-radius: 0.5rem;
  font-size: 1rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
  align-self: flex-start;
  
  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.3);
  }
  
  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
    transform: none;
  }
`;

const Result = styled.div`
  margin-top: 1rem;
  padding: 1rem;
  border-radius: 0.5rem;
  background: #f1f5f9;
  
  &.success {
    background: #dcfce7;
    border: 1px solid #bbf7d0;
  }
  
  &.error {
    background: #fee2e2;
    border: 1px solid #fecaca;
  }
`;

const ResultHeader = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
  font-weight: 500;
`;

function Integrations() {
  const [stripeData, setStripeData] = useState({
    amount: '',
    currency: 'usd',
    email: '',
    name: ''
  });
  
  const [googleData, setGoogleData] = useState({
    fileName: '',
    content: '',
    title: '',
    sheetData: ''
  });
  
  const [deepseekData, setDeepseekData] = useState({
    prompt: '',
    code: '',
    request: ''
  });
  
  const [results, setResults] = useState({});
  const [loading, setLoading] = useState({});

  const handleStripeSubmit = async (e) => {
    e.preventDefault();
    setLoading(prev => ({ ...prev, stripe: true }));
    
    try {
      // Create customer first
      const customerResult = await integrationsService.createStripeCustomer(
        stripeData.email,
        stripeData.name
      );
      
      // Then create payment intent
      const paymentResult = await integrationsService.createStripePaymentIntent(
        parseInt(stripeData.amount),
        stripeData.currency
      );
      
      setResults(prev => ({
        ...prev,
        stripe: {
          success: true,
          message: 'Stripe integration successful!',
          data: { customer: customerResult, payment: paymentResult }
        }
      }));
    } catch (error) {
      setResults(prev => ({
        ...prev,
        stripe: {
          success: false,
          message: `Error: ${error.response?.data?.detail || error.message}`
        }
      }));
    } finally {
      setLoading(prev => ({ ...prev, stripe: false }));
    }
  };

  const handleGoogleDriveSubmit = async (e) => {
    e.preventDefault();
    setLoading(prev => ({ ...prev, googleDrive: true }));
    
    try {
      const result = await integrationsService.createGoogleDriveFile(
        googleData.fileName,
        googleData.content
      );
      
      setResults(prev => ({
        ...prev,
        googleDrive: {
          success: true,
          message: 'Google Drive file created successfully!',
          data: result
        }
      }));
    } catch (error) {
      setResults(prev => ({
        ...prev,
        googleDrive: {
          success: false,
          message: `Error: ${error.response?.data?.detail || error.message}`
        }
      }));
    } finally {
      setLoading(prev => ({ ...prev, googleDrive: false }));
    }
  };

  const handleGoogleSheetSubmit = async (e) => {
    e.preventDefault();
    setLoading(prev => ({ ...prev, googleSheet: true }));
    
    try {
      const result = await integrationsService.createGoogleSheet(
        googleData.title,
        googleData.sheetData ? JSON.parse(googleData.sheetData) : null
      );
      
      setResults(prev => ({
        ...prev,
        googleSheet: {
          success: true,
          message: 'Google Sheet created successfully!',
          data: result
        }
      }));
    } catch (error) {
      setResults(prev => ({
        ...prev,
        googleSheet: {
          success: false,
          message: `Error: ${error.response?.data?.detail || error.message}`
        }
      }));
    } finally {
      setLoading(prev => ({ ...prev, googleSheet: false }));
    }
  };

  const handleDeepseekSubmit = async (e) => {
    e.preventDefault();
    setLoading(prev => ({ ...prev, deepseek: true }));
    
    try {
      const result = await integrationsService.generateCodeWithDeepSeek(
        deepseekData.prompt
      );
      
      setResults(prev => ({
        ...prev,
        deepseek: {
          success: true,
          message: 'Code generated with DeepSeek!',
          data: result
        }
      }));
    } catch (error) {
      setResults(prev => ({
        ...prev,
        deepseek: {
          success: false,
          message: `Error: ${error.response?.data?.detail || error.message}`
        }
      }));
    } finally {
      setLoading(prev => ({ ...prev, deepseek: false }));
    }
  };

  return (
    <Container>
      <Header>
        <Title>API Integrations</Title>
        <Subtitle>Connect your applications with popular services and AI providers</Subtitle>
      </Header>
      
      <IntegrationsGrid>
        {/* Stripe Integration */}
        <IntegrationCard>
          <CardHeader>
            <CardIcon>
              <CreditCard size={24} />
            </CardIcon>
            <CardTitle>Stripe Payments</CardTitle>
          </CardHeader>
          <CardDescription>
            Accept payments, create customers, and manage subscriptions with Stripe.
          </CardDescription>
          
          <Form onSubmit={handleStripeSubmit}>
            <FormGroup>
              <Label>Email</Label>
              <Input
                type="email"
                value={stripeData.email}
                onChange={(e) => setStripeData(prev => ({ ...prev, email: e.target.value }))}
                placeholder="user@example.com"
                required
              />
            </FormGroup>
            
            <FormGroup>
              <Label>Name</Label>
              <Input
                type="text"
                value={stripeData.name}
                onChange={(e) => setStripeData(prev => ({ ...prev, name: e.target.value }))}
                placeholder="John Doe"
                required
              />
            </FormGroup>
            
            <FormGroup>
              <Label>Amount (in cents)</Label>
              <Input
                type="number"
                value={stripeData.amount}
                onChange={(e) => setStripeData(prev => ({ ...prev, amount: e.target.value }))}
                placeholder="1000"
                required
              />
            </FormGroup>
            
            <Button type="submit" disabled={loading.stripe}>
              {loading.stripe ? 'Processing...' : 'Create Payment'}
            </Button>
          </Form>
          
          {results.stripe && (
            <Result className={results.stripe.success ? 'success' : 'error'}>
              <ResultHeader>
                {results.stripe.success ? <CheckCircle size={20} /> : <AlertCircle size={20} />}
                {results.stripe.message}
              </ResultHeader>
              {results.stripe.data && (
                <pre>{JSON.stringify(results.stripe.data, null, 2)}</pre>
              )}
            </Result>
          )}
        </IntegrationCard>
        
        {/* Google Drive Integration */}
        <IntegrationCard>
          <CardHeader>
            <CardIcon>
              <Database size={24} />
            </CardIcon>
            <CardTitle>Google Drive</CardTitle>
          </CardHeader>
          <CardDescription>
            Create and manage files in Google Drive from your applications.
          </CardDescription>
          
          <Form onSubmit={handleGoogleDriveSubmit}>
            <FormGroup>
              <Label>File Name</Label>
              <Input
                type="text"
                value={googleData.fileName}
                onChange={(e) => setGoogleData(prev => ({ ...prev, fileName: e.target.value }))}
                placeholder="my-document.txt"
                required
              />
            </FormGroup>
            
            <FormGroup>
              <Label>Content</Label>
              <TextArea
                value={googleData.content}
                onChange={(e) => setGoogleData(prev => ({ ...prev, content: e.target.value }))}
                placeholder="File content..."
                required
              />
            </FormGroup>
            
            <Button type="submit" disabled={loading.googleDrive}>
              {loading.googleDrive ? 'Creating...' : 'Create File'}
            </Button>
          </Form>
          
          {results.googleDrive && (
            <Result className={results.googleDrive.success ? 'success' : 'error'}>
              <ResultHeader>
                {results.googleDrive.success ? <CheckCircle size={20} /> : <AlertCircle size={20} />}
                {results.googleDrive.message}
              </ResultHeader>
              {results.googleDrive.data && (
                <pre>{JSON.stringify(results.googleDrive.data, null, 2)}</pre>
              )}
            </Result>
          )}
        </IntegrationCard>
        
        {/* Google Sheets Integration */}
        <IntegrationCard>
          <CardHeader>
            <CardIcon>
              <Grid size={24} />
            </CardIcon>
            <CardTitle>Google Sheets</CardTitle>
          </CardHeader>
          <CardDescription>
            Create and populate Google Sheets with your data.
          </CardDescription>
          
          <Form onSubmit={handleGoogleSheetSubmit}>
            <FormGroup>
              <Label>Sheet Title</Label>
              <Input
                type="text"
                value={googleData.title}
                onChange={(e) => setGoogleData(prev => ({ ...prev, title: e.target.value }))}
                placeholder="My Spreadsheet"
                required
              />
            </FormGroup>
            
            <FormGroup>
              <Label>Sheet Data (JSON array)</Label>
              <TextArea
                value={googleData.sheetData}
                onChange={(e) => setGoogleData(prev => ({ ...prev, sheetData: e.target.value }))}
                placeholder='[["Name", "Age"], ["John", 30], ["Jane", 25]]'
              />
            </FormGroup>
            
            <Button type="submit" disabled={loading.googleSheet}>
              {loading.googleSheet ? 'Creating...' : 'Create Sheet'}
            </Button>
          </Form>
          
          {results.googleSheet && (
            <Result className={results.googleSheet.success ? 'success' : 'error'}>
              <ResultHeader>
                {results.googleSheet.success ? <CheckCircle size={20} /> : <AlertCircle size={20} />}
                {results.googleSheet.message}
              </ResultHeader>
              {results.googleSheet.data && (
                <pre>{JSON.stringify(results.googleSheet.data, null, 2)}</pre>
              )}
            </Result>
          )}
        </IntegrationCard>
        
        {/* DeepSeek Integration */}
        <IntegrationCard>
          <CardHeader>
            <CardIcon>
              <Bot size={24} />
            </CardIcon>
            <CardTitle>DeepSeek AI</CardTitle>
          </CardHeader>
          <CardDescription>
            Generate code and get explanations using DeepSeek's powerful AI models.
          </CardDescription>
          
          <Form onSubmit={handleDeepseekSubmit}>
            <FormGroup>
              <Label>Prompt</Label>
              <TextArea
                value={deepseekData.prompt}
                onChange={(e) => setDeepseekData(prev => ({ ...prev, prompt: e.target.value }))}
                placeholder="Write a Python function to calculate fibonacci numbers..."
                required
              />
            </FormGroup>
            
            <Button type="submit" disabled={loading.deepseek}>
              {loading.deepseek ? 'Generating...' : 'Generate Code'}
            </Button>
          </Form>
          
          {results.deepseek && (
            <Result className={results.deepseek.success ? 'success' : 'error'}>
              <ResultHeader>
                {results.deepseek.success ? <CheckCircle size={20} /> : <AlertCircle size={20} />}
                {results.deepseek.message}
              </ResultHeader>
              {results.deepseek.data && (
                <pre>{results.deepseek.data.code || JSON.stringify(results.deepseek.data, null, 2)}</pre>
              )}
            </Result>
          )}
        </IntegrationCard>
      </IntegrationsGrid>
    </Container>
  );
}

export default Integrations;
